function img_fresneled = angler_spectrum(I, default_pixels, conf)  %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  % フレネル変換  % 複素振幅，crop前デフォルトピクセル数からフレネル伝搬の複素振幅を計算  % 角スペクトル法で算出  %%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%%  [h_orig, w_orig] = size(I); % 変換前サイズ  % ゼロパディング処理  % エイリアシングを防ぐため、計算領域を広げる  padding_rate = 5;  h = h_orig * padding_rate;  w = w_orig * padding_rate;  I_padded = zeros(h, w);  % 真ん中に元画像を配置する  y_start = floor((h - h_orig)/2) + 1;  x_start = floor((w - w_orig)/2) + 1;  I_padded(y_start : y_start+h_orig-1, x_start : x_start+w_orig-1) = I;  pixel_pich = conf.pixel_size * default_pixels / h_orig / conf.zoom_ratio;  nx = [-floor(w/2): ceil(w/2 - 1)];  ny = [-floor(h/2): ceil(h/2 - 1)];  u_index = nx / (w * pixel_pich);  v_index = ny / (h * pixel_pich);  [u_array, v_array] = meshgrid(u_index, v_index);  W = sqrt((1/conf.wavelength)^2 - u_array.^2 - v_array.^2);  H = exp(1i * 2 * pi * W * conf.fresnel_d);  F = fft2(I_padded);  F_shifted = fftshift(F);  U_shifted = F_shifted .* H;  U = ifftshift(U_shifted);  img_fresneled_padded = ifft2(U);  img_fresneled = img_fresneled_padded(y_start : y_start+h_orig-1, x_start : x_start+w_orig-1);end